import React from 'react';

const PanelEditorEmpresas = () => {
  const rubros = [
    'Comercio',
    'Tecnología',
    'Turismo',
    'Educación',
    'Salud',
    'Gastronomía',
    'Industria',
    'Artesanía',
    'Medios',
    'Construcción'
  ];

  return (
    <div className="bg-[#121212] w-full min-h-screen p-8">
  <h2 className="text-white text-xl font-semibold mb-4">rubro</h2>
  <div className="bg-black p-6 rounded-lg">
    <h3 className="text-white text-lg font-bold mb-4">nombre</h3>
    <div className="grid grid-cols-4 gap-4">
      {rubros.map((rubro, index) => (
        <input
          key={index}
          type="text"
          value={rubro}
          className="bg-white rounded-md px-4 py-2 w-full"
          readOnly
        />
      ))}
    </div>
    <div className="mt-6 flex justify-end">
      <button className="bg-lime-400 text-black font-semibold px-4 py-2 rounded-full hover:bg-lime-500 transition">
        + Añadir rubro
      </button>
    </div>
  </div>
</div>

  );
};

export default PanelEditorEmpresas;
